import{_ as t,c as i,a1 as a,o}from"./chunks/framework.BDxlaA_J.js";const h=JSON.parse('{"title":"Introduction to Information Security & Penetration Testing","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/0-core-knowledge/4-Infosec-101.md","filePath":"categories/ethical-hacking-labs/0-core-knowledge/4-Infosec-101.md"}'),n={name:"categories/ethical-hacking-labs/0-core-knowledge/4-Infosec-101.md"};function r(s,e,l,c,u,d){return o(),i("div",null,e[0]||(e[0]=[a('<h1 id="introduction-to-information-security-penetration-testing" tabindex="-1"><u>Introduction to Information Security &amp; Penetration Testing</u> <a class="header-anchor" href="#introduction-to-information-security-penetration-testing" aria-label="Permalink to &quot;&lt;u&gt;Introduction to Information Security &amp; Penetration Testing&lt;/u&gt;&quot;">​</a></h1><blockquote><p>⚠️ This module is fully theoretical and was extracted from <a href="https://github.com/Samsar4/CEH-v10-Study-Guide/" target="_blank" rel="noreferrer">CEH Study Guide</a> repo. Here you&#39;ll find some basic terms in &#39;InfoSec world&#39;.</p></blockquote><h2 id="fundamental-security-concepts" tabindex="-1"><u> Fundamental Security Concepts </u> <a class="header-anchor" href="#fundamental-security-concepts" aria-label="Permalink to &quot;&lt;u&gt; Fundamental Security Concepts &lt;/u&gt;&quot;">​</a></h2><p>The whole principle is to avoid <strong>Theft, Tampering and Disruption</strong> of the systems through <strong>CIA Triad</strong> (Confidentiality, Integrity and Availability).</p><p align="center"><img width="50%" src="https://i.ytimg.com/vi/AJTJN4wDBM8/hqdefault.jpg"></p><ul><li><p><strong>Confidentiality</strong> Keeping systems and data from being accessed, seen, read to anyone who is not authorized to do so.</p></li><li><p><strong>Integrity</strong> Protect the data from modification or deletion by unauthorized parties, and ensuring that when authorized people make changes that shouldn&#39;t have been made the damage can be undone.</p></li><li><p><strong>Availability</strong> Systems, access channels, and authentication mechanisms must all be working properly for the information they provide and protect to be available when needed.</p></li></ul><p><strong>Note:</strong> <em>In addition, other properties, such as authenticity, accountability, non-repudiation and reliability can also be involved. (ISO/IEC 27000:2009)</em></p><ul><li><p><strong>Auditing &amp; Accountability</strong> Basically keep tracking of everthing, like, who&#39;s been logging in when are they loggin in whose access this data.</p></li><li><p><strong>Non-Repudiation</strong> Non-repudiation is the assurance that someone cannot deny the validity of something. Non-repudiation is a legal concept that is widely used in information security and refers to a service, which provides proof of the origin of data and the integrity of the data.</p></li></ul><h3 id="security-functionality-and-usability-balance" tabindex="-1"><strong>Security, Functionality and Usability balance</strong> <a class="header-anchor" href="#security-functionality-and-usability-balance" aria-label="Permalink to &quot;**Security, Functionality and Usability balance**&quot;">​</a></h3><p>There is an inter dependency between these three attributes. When <strong>security goes up, usability and functionality come down</strong>. Any organization should balance between these three qualities to arrive at a balanced information system.</p><p align="center"><img width="50%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f14455ed4def635e1bc93b85657f43dbbf4a3127/triad2.png"></p><h2 id="types-of-hackers" tabindex="-1"><u>Types of Hackers</u> <a class="header-anchor" href="#types-of-hackers" aria-label="Permalink to &quot;&lt;u&gt;Types of Hackers&lt;/u&gt;&quot;">​</a></h2><p align="center"><img width="50%" src="https://www.simplilearn.com/ice9/free_resources_article_thumb/types-hacker.JPG"></p><blockquote><ul><li><strong>Black Hat</strong> - Hackers that seek to perform malicious activities.</li><li><strong>Gray Hat</strong> - Hackers that perform good or bad activities but do not have the permission of the organization they are hacking against.</li><li><strong>White Hat</strong> - Ethical hackers; They use their skills to improve security by exposing vulnerabilities before malicious hackers.</li></ul></blockquote><p><strong>Script Kiddie / Skiddies</strong> - Unskilled individual who uses malicious scripts or programs, such as a web shell, developed by others to attack computer systems and networks and deface websites.</p><p><strong>State-Sponsored Hacker</strong> - Hacker that is hired by a government or entity related.</p><p><strong>Hacktivist</strong> - Someone who hacks for a cause; political agenda.</p><p><strong>Suicide Hackers</strong> - Are hackers that are not afraid of going jail or facing any sort of punishment; hack to get the job done.</p><p><strong>Cyberterrorist</strong> - Motivated by religious or political beliefs to create fear or disruption.</p><h2 id="hacking-vocabulary" tabindex="-1"><u>Hacking Vocabulary</u> <a class="header-anchor" href="#hacking-vocabulary" aria-label="Permalink to &quot;&lt;u&gt;Hacking Vocabulary&lt;/u&gt;&quot;">​</a></h2><ul><li><strong>Hack value</strong> - Perceived value or worth of a target as seen by the attacker.</li><li><strong>Vulnerability</strong> - A system flaw, weakness on the system (on design, implementation etc).</li><li><strong>Threat</strong> - Exploits a vulnerability.</li><li><strong>Exploit</strong> - Exploits are a way of gaining access to a system through a security flaw and taking advantage of the flaw for their benefit.</li><li><strong>Payload</strong> - Component of an attack; is the part of the private user text which could also contain malware such as worms or viruses which performs the malicious action; deleting data, sending spam or encrypting data.</li><li><strong>Zero-day attack</strong> - Attack that occurs before a vendor knows or is able to patch a flaw.</li><li><strong>Daisy Chaining / Pivotting</strong> - It involves gaining access to a network and /or computer and then using the same information to gain access to multiple networks and computers that contains desirable information.</li><li><strong>Doxxing</strong> - Publishing PII about an individual usually with a malicious intent.</li><li><strong>Enterprise Information Security Architecture</strong> (EISA) - determines the structure and behavior of organization&#39;s information systems through processes, requirements, principles and models.</li></ul><h2 id="threat-categories" tabindex="-1"><u> Threat Categories </u> <a class="header-anchor" href="#threat-categories" aria-label="Permalink to &quot;&lt;u&gt; Threat Categories &lt;/u&gt;&quot;">​</a></h2><ul><li><p><strong>Network Threats</strong></p><ul><li>Information gathering</li><li>Sniffing and eavesdropping</li><li>DNS/ARP Poisoning</li><li>MITM (Man-in-the-Middle Attack)</li><li>DoS/DDoS</li><li>Password-based attacks</li><li>Firewall and IDS attack</li><li>Session Hijacking</li></ul></li><li><p><strong>Host Threats</strong></p><ul><li>Password cracking</li><li>Malware attacks</li><li>Footprinting</li><li>Profiling</li><li>Arbitrary code execution</li><li>Backdoor access</li><li>Privilege Escalation</li><li>Code Execution</li></ul></li><li><p><strong>Application Threats</strong></p><ul><li>Injection Attacks</li><li>Improper data/input validation</li><li>Improper error handling and exeception management</li><li>Hidden-field manipulation</li><li>Broken session management</li><li>Cryptography issues</li><li>SQL injection</li><li>Phishing</li><li>Buffer Overflow</li><li>Information disclosure</li><li>Security Misconfigurations</li></ul></li></ul><h2 id="attack-vectors" tabindex="-1"><u> Attack Vectors </u> <a class="header-anchor" href="#attack-vectors" aria-label="Permalink to &quot;&lt;u&gt; Attack Vectors &lt;/u&gt;&quot;">​</a></h2><p><em>Path by which a hacker can gain access to a host in order to deliver a payload or malicious outcome</em></p><ul><li><p><strong>APT - Advanced Persistent Threats</strong></p><ul><li>An advanced persistent threat is a stealthy threat actor, typically a nation state or state-sponsored group, which gains unauthorized access to a computer network and remains undetected for an extended period; Typically uses zero day attacks.</li></ul></li><li><p><strong>Cloud computing / Cloud based technologies</strong></p><ul><li>Flaw in one client&#39;s application cloud allow attacker to access other client&#39;s data</li></ul></li><li><p><strong>Viruses, worms, and malware</strong></p><ul><li>Viruses and worms are the most prevalent networking threat that are capable of infecting a network within seconds.</li></ul></li><li><p><strong>Ransomware</strong></p><ul><li>Restricts access to the computer system&#39;s files and folders and demands an online ransom payment to the attacker in order to remove the restrictions.</li></ul></li><li><p><strong>Mobile Device threats</strong></p></li><li><p><strong>Botnets</strong></p><ul><li>Huge network of compromised systems used by an intruder to perform various network attacks</li></ul></li><li><p><strong>Insider attacks</strong></p><ul><li>Disgruntled employee can damage assets from inside.</li><li>Huge network of compromised hosts. (used for DDoS).</li></ul></li><li><p><strong>Phishing attacks</strong></p></li><li><p><strong>Web Application Threats</strong></p><ul><li>Attacks like SQL injection, XSS (Cross-site scripting)...</li></ul></li><li><p><strong>IoT Threats</strong></p></li></ul><h2 id="attack-types" tabindex="-1"><u>Attack Types</u> <a class="header-anchor" href="#attack-types" aria-label="Permalink to &quot;&lt;u&gt;Attack Types&lt;/u&gt;&quot;">​</a></h2><h3 id="_1-operating-system" tabindex="-1">1. Operating System <a class="header-anchor" href="#_1-operating-system" aria-label="Permalink to &quot;1. Operating System&quot;">​</a></h3><p><em>Attacks targeting OS flaws or security issues inside such as guest accounts or default passwords.</em></p><blockquote><ul><li><strong>Vectors</strong>: Buffer overflows, Protocol Implementations, software defects, patch levels, authentication schemes</li></ul></blockquote><h3 id="_2-application-level" tabindex="-1">2. Application Level <a class="header-anchor" href="#_2-application-level" aria-label="Permalink to &quot;2. Application Level&quot;">​</a></h3><p><em>Attacks on programming code and software logic.</em></p><blockquote><ul><li><strong>Vectors</strong>: Buffer overflows, Bugs, XSS, DoS, SQL Injection, MitM</li></ul></blockquote><h3 id="_3-misconfiguration" tabindex="-1">3. Misconfiguration <a class="header-anchor" href="#_3-misconfiguration" aria-label="Permalink to &quot;3. Misconfiguration&quot;">​</a></h3><p><em>Attack takes advantage of systems that are misconfigured due to improper configuration or default configuration.</em></p><blockquote><ul><li><strong>Examples</strong>: Improper permissions of SQL users; Access-list permit all</li></ul></blockquote><h3 id="_4-shrink-wrap-code" tabindex="-1">4. Shrink-Wrap Code <a class="header-anchor" href="#_4-shrink-wrap-code" aria-label="Permalink to &quot;4. Shrink-Wrap Code&quot;">​</a></h3><p><em>Act of exploiting holes in unpatched or poorly-configured software.</em></p><blockquote><ul><li><strong>Examples</strong>: Software defect in version 1.0; DEfect in example CGI scripts; Default passwords</li></ul></blockquote><h2 id="vulnerabilities" tabindex="-1"><u>Vulnerabilities</u> <a class="header-anchor" href="#vulnerabilities" aria-label="Permalink to &quot;&lt;u&gt;Vulnerabilities&lt;/u&gt;&quot;">​</a></h2><ul><li><strong>CVSS - Common Vulnerability Scoring System</strong> <a href="https://nvd.nist.gov/vuln-metrics/cvss" target="_blank" rel="noreferrer">[+]</a><ul><li>Places numerical score based on severity</li><li><img src="https://3.bp.blogspot.com/-5V1cb_wTvsk/Wl78iF4Sd8I/AAAAAAAAF7U/KmK4pMXi54YworDgh4uI8aZtHgy0bbznQCLcBGAs/s1600/CVSS.png" alt="cvss"></li></ul></li><li><strong>CVE – Common Vulnerabilities and Exposures</strong> <a href="https://cve.mitre.org/" target="_blank" rel="noreferrer">[+]</a><ul><li>Is a list of publicly disclosed vulnerabilities and exposures that is maintained by MITRE.</li><li><img src="https://i0.wp.com/gbhackers.com/wp-content/uploads/2016/10/cve.png?resize=486%2C408&amp;ssl=1" alt="cve"></li></ul></li><li><strong>NVD - National Vulnerability Database</strong> <a href="https://nvd.nist.gov/" target="_blank" rel="noreferrer">[+]</a><ul><li>is a database, maintained by NIST, that is fully synchronized with the MITRE CVE list; US Gov. vulnerabilities repository.</li></ul></li></ul><h3 id="vulnerability-categories" tabindex="-1">Vulnerability Categories <a class="header-anchor" href="#vulnerability-categories" aria-label="Permalink to &quot;Vulnerability Categories&quot;">​</a></h3><ul><li><strong>Misconfiguration</strong> - improperly configuring a service or application</li><li><strong>Default installation</strong> - failure to change settings in an application that come by default</li><li><strong>Buffer overflow</strong> - code execution flaw</li><li><strong>Missing patches</strong> - systems that have not been patched</li><li><strong>Design flaws</strong> - flaws inherent to system design such as encryption and data validation</li><li><strong>Operating System Flaws</strong> - flaws specific to each OS</li><li><strong>Default passwords</strong> - leaving default passwords that come with system/application</li></ul><h2 id="pen-test-phases-ceh-method" tabindex="-1"><u>Pen Test Phases (CEH method)</u> <a class="header-anchor" href="#pen-test-phases-ceh-method" aria-label="Permalink to &quot;&lt;u&gt;Pen Test Phases (CEH method)&lt;/u&gt;&quot;">​</a></h2><ol><li><strong>Pre-Attack Phase</strong> - Reconnaissance and data-gathering.</li><li><strong>Attack Phase</strong> - Attempts to penetrate the network and execute attacks.</li><li><strong>Post-Attack Phase</strong> - Cleanup to return a system to the pre-attack condition and deliver reports.</li></ol><h2 id="the-five-stages-of-ethical-hacking" tabindex="-1"><u>The Five Stages of Ethical Hacking</u> <a class="header-anchor" href="#the-five-stages-of-ethical-hacking" aria-label="Permalink to &quot;&lt;u&gt;The Five Stages of Ethical Hacking&lt;/u&gt;&quot;">​</a></h2><h3 id="_1-reconnaissance" tabindex="-1">1. <strong>Reconnaissance</strong> <a class="header-anchor" href="#_1-reconnaissance" aria-label="Permalink to &quot;1. **Reconnaissance**&quot;">​</a></h3><p><em>Gathering evidence about targets</em>; There are two types of Recon:</p><ul><li><strong>Passive Reconnaissance</strong>: Gain information about targeted computers and networks <strong>without direct interaction with the systems</strong>. <ul><li>e.g: Google Search, Public records, New releases, Social Media, Wardrive scanning networks around.</li></ul></li><li><strong>Active Reconnaissance</strong>: Envolves direct interaction with the target. <ul><li>e.g: Make a phone call to the target, Job interview; tools like Nmap, Nessus, OpenVAS, Nikto and Metasploit can be considered as Active Recon.</li></ul></li></ul><h3 id="_2-scanning-enumeration" tabindex="-1">2. <strong>Scanning &amp; Enumeration</strong> <a class="header-anchor" href="#_2-scanning-enumeration" aria-label="Permalink to &quot;2. **Scanning &amp; Enumeration**&quot;">​</a></h3><p><em>Obtaining more in-depth information about targets.</em></p><ul><li>e.g: Network Scanning, Port Scanning, Which versions of services are running.</li></ul><h3 id="_3-gaining-access" tabindex="-1">3. <strong>Gaining Access</strong> <a class="header-anchor" href="#_3-gaining-access" aria-label="Permalink to &quot;3. **Gaining Access**&quot;">​</a></h3><p><em>Attacks are leveled in order to gain access to a system.</em></p><ul><li>e.g: Can be done locally (offline), over a LAN or over the internet. <ul><li>e.g(2): Spoofing to exploit the system by pretending to be a legitimate user or different systems, they can send a data packet containing a bug to the target system in order to exploit a vulnerability.</li><li>Can be done using many techniques like command injection, buffer overflow, DoS, brute forcing credentials, social engineering, misconfigurations etc.</li></ul></li></ul><h3 id="_4-maintaining-access" tabindex="-1">4. <strong>Maintaining Access</strong> <a class="header-anchor" href="#_4-maintaining-access" aria-label="Permalink to &quot;4. **Maintaining Access**&quot;">​</a></h3><p><em>Items put in place to ensure future access.</em></p><ul><li>e.g: Rookit, Trojan, Backdoor can be used.</li></ul><h3 id="_5-covering-tracks" tabindex="-1">5. <strong>Covering Tracks</strong> <a class="header-anchor" href="#_5-covering-tracks" aria-label="Permalink to &quot;5. **Covering Tracks**&quot;">​</a></h3><p><em>Steps taken to conceal success and intrusion; Not be noticed.</em></p><ul><li>e.g: Clear the logs; Obfuscate trojans or malicious backdoors programs.</li></ul><h2 id="three-types-of-active-defense" tabindex="-1">Three Types of Active Defense <a class="header-anchor" href="#three-types-of-active-defense" aria-label="Permalink to &quot;Three Types of Active Defense&quot;">​</a></h2><ul><li><strong>Annoyance</strong><ul><li>Involves tracking a hacker and leading him into a fake server, wasting his time — and making him easy to detect.</li></ul></li><li><strong>Attribution</strong><ul><li>Identify an attacker; Uses tools to trace the source of an attack back to a specific location, or even an individual hacker.</li></ul></li><li><strong>Attack</strong><ul><li>That is most controversial. To “hack back,” a company accesses an alleged hacker’s computer to delete its data or even to take revenge. Both of these steps are considered illegal.</li></ul></li></ul><h2 id="information-assurance-ia" tabindex="-1"><u> Information Assurance (IA) </u> <a class="header-anchor" href="#information-assurance-ia" aria-label="Permalink to &quot;&lt;u&gt; Information Assurance (IA) &lt;/u&gt;&quot;">​</a></h2><p><em>Refers to the assurance of the Integrity, Availability, confidentiality, and authenticity of information and information systems during usage, processing, storage and transmission of information.</em></p><ul><li><strong>Processes that help achieving IA:</strong><ul><li>Developing local policy, process, and guidance.</li><li>Designing network and user authetication strategy.</li><li>Identifying network vulnerabilities and threats (Vulnerability assessments outline the security posture of the network).</li><li>Idenfitying problems and resource requirements.</li><li>Creating plan for identified resource requirements.</li><li>Applying appropriate IA controls.</li><li>Performing C&amp;A (Certification and Accreditation) process of information systems helps to trace vulnerabilities, and implement sa fety measures.</li><li>Providing information assurance training to all personnel in federal and private org.</li></ul></li></ul><h2 id="information-security-management-program" tabindex="-1"><u>Information Security Management Program </u> <a class="header-anchor" href="#information-security-management-program" aria-label="Permalink to &quot;&lt;u&gt;Information Security Management Program &lt;/u&gt;&quot;">​</a></h2><p><em>Combination of policies, processes, procedures, standards, and guidelines to establish the required <strong>level of information security.</strong></em></p><ul><li>Designed to ensure the business operates in a state of reduced risk.</li><li>It encompasses all organizational and operational processes and participants relevant to information security.</li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/950220d4b802bb726fe84470c7a13055b056a621/infosec.jpg" alt="infosec"></p><blockquote><p>⚠️ <strong>IA</strong> focus on risk assessment, mitigation side of things; ⚠️ <strong>InfoSec</strong> focus on actually implementing security measures to safeguard systems.</p></blockquote><h2 id="eisa-enterprise-information-security-architecture" tabindex="-1"><u>EISA - Enterprise Information Security Architecture</u> <a class="header-anchor" href="#eisa-enterprise-information-security-architecture" aria-label="Permalink to &quot;&lt;u&gt;EISA - Enterprise Information Security Architecture&lt;/u&gt;&quot;">​</a></h2><p><em>Set of requirements, process, principles, and models that determines the structure and behavior of an organization&#39;s information systems.</em></p><ul><li><strong>Goals of EISA</strong>: <ul><li>Help in monitoring and detecting network behaviors</li><li>Detect and recover from security breaches</li><li>Prioritizing resources of an organization</li><li>Help to perform risk assessment of an organization&#39;s IT assets.</li><li>Cost prospective when incorporated in security provisions such as incident response, disaster recovery, event correlation, etc.</li></ul></li></ul><h2 id="physical-security-controls" tabindex="-1"><u>Physical Security Controls</u> <a class="header-anchor" href="#physical-security-controls" aria-label="Permalink to &quot;&lt;u&gt;Physical Security Controls&lt;/u&gt;&quot;">​</a></h2><ul><li><p><strong>Preventive control</strong>: Deters the actor from performing the threat.</p><ul><li>e.g: Fence, Server Locks, Mantraps, etc.</li></ul></li><li><p><strong>Detective control</strong>: Recognizes an actor&#39;s threat.</p><ul><li>e.g: Background check, CCTV.</li></ul></li><li><p><strong>Deterrent control</strong>: Deters the actor from <strong>attempting</strong> the threat.</p><ul><li>e.g: Warning Sign.</li></ul></li><li><p><strong>Recovery</strong>: Mitigates the impact of a manifested threat.</p><ul><li>e.g: Backups.</li></ul></li><li><p><strong>Compensating control</strong>: Provides alternative fixes to any of the above functions.</p></li></ul><p><em>Most of security controls are preventive phase controls</em>.</p><p>⚠️ <strong>Defense in Depth</strong>: Multiple layers of security controls; Provides redundancy in the event of a control failure. (e.g.: image below)</p><p><img src="https://www.fairwarning.com/wp-content/uploads/2019/03/Defense-in-Depth-for-Cloud-Security-Rainbow-Diagram.png" alt="defense-in-depth"></p><h3 id="types-of-security-controls" tabindex="-1">Types of Security Controls <a class="header-anchor" href="#types-of-security-controls" aria-label="Permalink to &quot;Types of  Security Controls&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Physical</strong></td><td>Guards, lights, cameras, fire extinguishers, flood protection</td></tr><tr><td><strong>Administrative</strong></td><td>Training awareness, policies, procedures and guidelines to infosec</td></tr><tr><td><strong>Technical</strong></td><td>IDS/IPS, Firewall, Encryption, Smart cards, Access control lists</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Preventative</strong></td><td>authentication, alarm bells</td></tr><tr><td><strong>Detective</strong></td><td>audits, backups</td></tr><tr><td><strong>Corrective</strong></td><td>restore operations</td></tr></tbody></table><h2 id="managing-the-risk" tabindex="-1"><u>Managing the Risk</u> <a class="header-anchor" href="#managing-the-risk" aria-label="Permalink to &quot;&lt;u&gt;Managing the Risk&lt;/u&gt;&quot;">​</a></h2><p><strong>Risk</strong> can be defined as a probability of the occurrence of a threat or an event that may damage, or cause loss or have other negative impact either from internal or external liabilities.</p><h3 id="risk-matrix" tabindex="-1">Risk matrix <a class="header-anchor" href="#risk-matrix" aria-label="Permalink to &quot;Risk matrix&quot;">​</a></h3><p>A <strong>risk matrix</strong> is used during <strong>risk assessment</strong> to define the level of risk by considering the category of <strong>probability or likelihood</strong> against the category of consequence <strong>severity</strong>.</p><ul><li>This is a simple mechanism to increase visibility of risks and assist management decision making.</li></ul><p><img src="https://paladinrisk.com.au/wp-content/uploads/2018/11/risk-1-1024x434.jpg" alt="matrix"></p><h3 id="risk-management" tabindex="-1">Risk Management <a class="header-anchor" href="#risk-management" aria-label="Permalink to &quot;Risk Management&quot;">​</a></h3><p><em>Is the identification, evaluation, and prioritization of risks followed by coordinated and economical application of resources to minimize, monitor, and control the probability or impact of unfortunate events or to maximize the realization of opportunities.</em></p><h2 id="security-policies" tabindex="-1"><u>Security Policies</u> <a class="header-anchor" href="#security-policies" aria-label="Permalink to &quot;&lt;u&gt;Security Policies&lt;/u&gt;&quot;">​</a></h2><ol><li><strong>Policies</strong> - High-level statements about protecting information; Business rules to safeguard CIA triad; Security Policies can be applied on Users, Systems, Partners, Networks, and Providers. <ul><li><strong>Common Security Policies examples:</strong><ul><li>Password Policy <ul><li>Meet the password complexity requirements.</li><li>e.g: Minimum 8 char length, upper and lower case and alphanumerical.</li></ul></li><li>Wireless Security Policy</li><li>AUP - Acceptable Use-Policy <ul><li>How to properly use company&#39;s assets</li><li>e.g: &quot;Do&#39;s and Dont&#39;s&quot; with company&#39;s computer.</li></ul></li><li>Data Retention Policy <ul><li>e.g: Keep the data for X time.</li></ul></li><li>Access Control Policies <ul><li>e.g: Accessing servers; Firewalls</li></ul></li></ul></li></ul></li><li><strong>Procedures</strong> - Set of details steps to accomplish a goal; Instructions for implementation</li><li><strong>Guidelines</strong> - Advice on actions given a situation; Recommended, not mandatory</li></ol><h2 id="security-policy-examples" tabindex="-1">Security Policy - Examples <a class="header-anchor" href="#security-policy-examples" aria-label="Permalink to &quot;Security Policy - Examples&quot;">​</a></h2><ul><li><p><strong>Access Control Policy</strong></p><ul><li>This defines the resources being protected and the rules that control access to them</li></ul></li><li><p><strong>Remote Access Policy</strong></p><ul><li>This defines who can have remote access and defines access medium and remote access security controls.</li></ul></li><li><p><strong>Firewall Management Policy</strong></p><ul><li>This defines access, management and monitoring of firewalls in an organization.</li></ul></li><li><p><strong>Network Connection Policy</strong></p><ul><li>This defines who can install new resources on the network, approve the installation of new devices, document network changes etc.</li></ul></li><li><p><strong>Password Policy</strong></p><ul><li>This defines guidelines for using strong password protection on available resources.</li></ul></li><li><p><strong>User Account Policy</strong></p><ul><li>This defines the account creation process, authority, rights and responsibility of user accounts.</li></ul></li><li><p><strong>Information Protection Policy</strong></p><ul><li>This defines the sensitivity levels of information, who may have access, how it is stored and transmitted, and how it should be deleted from storage media etc.</li></ul></li><li><p><strong>Special Access Policy</strong></p><ul><li>This defines the terms and conditions of granting special access to system resources.</li></ul></li><li><p><strong>Email Security Policy</strong></p><ul><li>This policy is designed to govern the proper usage of corporate email.</li></ul></li><li><p><strong>Acceptable Use Policy</strong></p><ul><li>This defines the acceptable use of system resources.</li></ul></li></ul><h2 id="security-policiy-types" tabindex="-1">Security Policiy - Types <a class="header-anchor" href="#security-policiy-types" aria-label="Permalink to &quot;Security Policiy - Types&quot;">​</a></h2><ol><li><p><strong>Promiscuous Policy</strong> - This policy usually has no restrictions on usage of system resources.</p></li><li><p><strong>Permissive Policy</strong> - This policy begins wide open and only know dangerous services/attacks or behaviors are blocked. This type of policy has to be updated regularly to stay effective.</p></li><li><p><strong>Prudent Policy</strong> - This policy provides maximum security while allowing known but necessary dangers. This type of policy will block all services and only safe/necessary services are enabled individually. Everything is logged.</p></li><li><p><strong>Paranoid Policy</strong> - This policy forbids everything. No Internet connection or severely restricted Internet usage is allowed.</p></li></ol><h2 id="security-policy-creation-steps" tabindex="-1">Security Policy - Creation Steps <a class="header-anchor" href="#security-policy-creation-steps" aria-label="Permalink to &quot;Security Policy - Creation Steps&quot;">​</a></h2><ol><li>Perform a Risk Assessment</li><li>Use security Standards and Frameworks as guide</li><li>Get Management and Staff input</li><li>Enforce the policy. Use penalties for non-compliance</li><li>Publish final draft to entire org.</li><li>Have all staff read/sign that they understood policy</li><li>Employ tools to help enforce policy</li><li>Staff training</li><li>Review and update regularly</li></ol><h2 id="incident-management-process" tabindex="-1"><u>Incident Management Process</u> <a class="header-anchor" href="#incident-management-process" aria-label="Permalink to &quot;&lt;u&gt;Incident Management Process&lt;/u&gt;&quot;">​</a></h2><p><em>An incident is an event that could lead to loss of, or disruption to, an organization&#39;s operations, services or functions.</em></p><p><em><strong>Incident management</strong> is a term describing the activities of an organization to identify, analyze, and correct hazards to prevent a future re-occurrence.</em></p><ol><li><strong>Preparation:</strong> Select people, assign rules, define tools to handle the incident.</li><li><strong>Detection &amp; Analysis:</strong> Determine an incident has ocurred (IDS, SIEM, AV, Someone reporting, etc).</li><li><strong>Classification and Prioritization:</strong></li><li><strong>Notification:</strong> Identify minor and major incident; who and how to notify an incident.</li><li><strong>Containment:</strong> Limit the damage; Isolate hosts; Contact system owners.</li><li><strong>Forensic Investigation:</strong> Investigate the root cause of the incident using forensic tools; System logs, real-time memory, network device logs, application logs, etc;</li><li><strong>Eradicate &amp; Recovery:</strong> Remove the cause of incident; Patch if needed. Recovery: get back into production; Monitor affected systems.</li><li><strong>Post-incident Activities:</strong> Document what happened and why; Transfer knowledge.</li></ol><h3 id="incident-response-team-duties" tabindex="-1">Incident Response Team Duties <a class="header-anchor" href="#incident-response-team-duties" aria-label="Permalink to &quot;Incident Response Team Duties&quot;">​</a></h3><ol><li>Managing security issues by taking a proactive approach towards the customer&#39;s security vulnerabilities</li><li>Developing or reviewing processes and procedures that must be followed</li><li>Managing the response to an incident and ensuring that all procedures are followed correctly in order to minimize and control the damage</li><li>Identifying and analyzing what has happened during an incident, including impact and threat</li><li>Providing a single point of contact for reporting seucirty incidents and issues</li><li>Reviewing changes in legal and regulatory requirements to ensure that all processes and procedures are valid</li><li>Reviewing existing controls and recommending steps and technologies to prevent future incidents</li><li>Establishing relationship with local law enforcement agency, gov. agencies, key partners and suppliers</li></ol><h3 id="siem-security-information-and-event-management" tabindex="-1">SIEM - Security Information and Event Management <a class="header-anchor" href="#siem-security-information-and-event-management" aria-label="Permalink to &quot;SIEM -  Security Information and Event Management&quot;">​</a></h3><p align="center"><img width="90%" src="https://secureops.com/wp-content/uploads/2020/01/components-of-siem.jpg"></p><p><em>Collects data points from network, including log files, traffic captures, SNMP messages, and so on, from every host on the network. SIEM can collect all this data into one centralized location and correlate it for analysis to look for security and performance issues, as well negative trends all in real time.</em></p><ul><li><p><strong>Aggregation</strong>: Collecting data from disparate sources and organizing the data into a single format. Any device within a SIEM system that collects data is called collector or an aggregator.</p></li><li><p><strong>Correlation</strong>: Is the logic that looks at data from disparate sources and can make determinations about events taking place on your network. (Could be in-band or out-of-band, depending on the placement of the NIDS/NIPS).</p><ul><li><strong>Alerts</strong> - For notification if something goes bad.</li><li><strong>Triggering</strong> - Exceeding thresholds.</li></ul></li><li><p><strong>Normalization</strong>: Will actually create multiple tables / organize in such a way that the data can become more efficient and allows our analysis and reports tools to work better.</p></li><li><p><strong>WORM - Write Once Read Many</strong>: The concept being is that log files are precious, and a lot of times you might want to look at them in an archival way, so that we can use optical media like WORM drives to store them.</p></li></ul><h4 id="most-popular-siem-tools" tabindex="-1">Most Popular SIEM Tools: <a class="header-anchor" href="#most-popular-siem-tools" aria-label="Permalink to &quot;Most Popular SIEM Tools:&quot;">​</a></h4><ul><li><p><strong><a href="https://www.splunk.com/" target="_blank" rel="noreferrer">Splunk</a></strong><img src="https://www.splunk.com/content/dam/splunk2/images/screenshots/platform-journey/conflaunch/SS-UI-Light-Mode-frame.png" alt="splunk"></p></li><li><p><strong><a href="https://www.microfocus.com/en-us/products/siem-security-information-event-management/overview" target="_blank" rel="noreferrer">ArcSight</a></strong><img src="https://i.ytimg.com/vi/N7J0EwdbKF0/maxresdefault.jpg" alt="arcsight"></p></li><li><p><strong><a href="https://www.elastic.co/what-is/elk-stack" target="_blank" rel="noreferrer">ELK - Elastic Search, Log Stash and Kibana</a> (Open Source)</strong><img src="https://i.imgur.com/lydtCwn.png" alt="elk"></p></li></ul><h2 id="identity-and-access-management" tabindex="-1"><u>Identity and Access Management</u> <a class="header-anchor" href="#identity-and-access-management" aria-label="Permalink to &quot;&lt;u&gt;Identity and Access Management&lt;/u&gt;&quot;">​</a></h2><blockquote><p><strong>Identification, Authentication, Authorization</strong>, and <strong>Accounting</strong> work together to manage assets securely.</p></blockquote><h3 id="_1-identification" tabindex="-1">1. <strong>Identification</strong> <a class="header-anchor" href="#_1-identification" aria-label="Permalink to &quot;1. **Identification**&quot;">​</a></h3><p><em>The information on credentials identifies the user.</em></p><ul><li><strong>Example</strong>: <ul><li>Your name, username, ID number, employee number, SSN etc.</li></ul></li></ul><h3 id="_2-authentication" tabindex="-1">2. <strong>Authentication</strong> <a class="header-anchor" href="#_2-authentication" aria-label="Permalink to &quot;2. **Authentication**&quot;">​</a></h3><p><em>“Prove you are the legitimate User&quot;. – Should always be done with Multifactor Authentication!</em></p><ul><li><strong>Authentication Factors:</strong><ul><li>Something you <strong>know</strong> (e.g. - password)</li><li>Something you <strong>have</strong> (e.g. - smart card)</li><li>Something you <strong>are</strong> (e.g. - fingerprint)</li><li>Something you <strong>do</strong> (e.g. - android pattern; manual signature)</li><li><strong>Somewhere</strong> you are (e.g. - geolocation)</li></ul></li></ul><blockquote><p>🛑 <strong>Multi-factor authentication</strong> <em>generally uses two of this examples (e.g. - Something you <strong>Know(1)</strong> and Something you <strong>Have(2)</strong>, never on same category</em></p></blockquote><h3 id="_3-authorization-concepts" tabindex="-1">3. Authorization concepts <a class="header-anchor" href="#_3-authorization-concepts" aria-label="Permalink to &quot;3. Authorization concepts&quot;">​</a></h3><p><em>What are you allowed to access – We use Access Control models, what and how we implement depends on the organization and what our security goals are.</em></p><ul><li><strong>Permissions</strong>: <ul><li>Applied to resources</li></ul></li><li><strong>Rights</strong> / <strong>Privileges</strong>: <ul><li>Assign at system level</li></ul></li><li><strong>Authorization strategies</strong>: <ul><li>Least privileged</li><li>Separation of Duties</li></ul></li></ul><h3 id="_4-accouting" tabindex="-1">4. Accouting <a class="header-anchor" href="#_4-accouting" aria-label="Permalink to &quot;4. Accouting&quot;">​</a></h3><p><em>Trace an Action to a Subjects Identity:</em></p><ul><li>Prove who/what a given action was performed by (non-repudiation); Logging</li></ul><h3 id="access-controls-models" tabindex="-1">Access Controls Models <a class="header-anchor" href="#access-controls-models" aria-label="Permalink to &quot;Access Controls Models&quot;">​</a></h3><p align="center"><img width="80%" src="https://security-architect.com/wp-content/uploads/FGA.png"></p><ul><li><strong>Mandatory Access Control (MAC)</strong>: <ul><li>Every object gets a <strong>label</strong><ul><li>Confidential, secret, top secret, etc</li></ul></li><li>The administrator decides who gets access to what security level; Users cannot change these settings</li><li>Used on old systems (e.g. Top Secret Gov. information)</li></ul></li><li><strong>Discretionary Access Control (DAC)</strong>: <ul><li>Used in most OS</li><li>Owner of the data defines access</li><li>Very flexible access control; Very weak security</li></ul></li><li><strong>Role-based Access Control (RBAC)</strong>: <ul><li>Access to resources is defines by a set of rules defined by a role in your organization/job function (Manager, Director etc)</li><li>Administrators provide access based on the role of the user <ul><li>Rights are gained implicity instead of explicity</li></ul></li><li>In Windows, use <strong>Groups</strong> to provide role-based access control <ul><li>e.g. Admin Groups --&gt; Rights and Perms,</li><li>Sales Group --&gt; Rights and Perms</li></ul></li></ul></li></ul><blockquote><p>⚠️ <strong>Access is defined by ACL, Access Control List</strong>. ⚠️ <strong>Implicity deny</strong> prevents access unless specifically permitted.</p></blockquote><h2 id="data-loss-prevention-dlp" tabindex="-1">Data Loss Prevention (DLP) <a class="header-anchor" href="#data-loss-prevention-dlp" aria-label="Permalink to &quot;Data Loss Prevention (DLP)&quot;">​</a></h2><p>Data Loss Prevention (DLP) is the practice of <strong>detecting and preventing data breaches, exfiltration, or unwanted destruction of sensitive data</strong>. Organizations use DLP to protect and secure their data and comply with regulations.</p><ul><li>The DLP term refers to defending organizations against both data loss and data leakage prevention.</li></ul><h4 id="organizations-typically-use-dlp-to" tabindex="-1">Organizations typically use DLP to: <a class="header-anchor" href="#organizations-typically-use-dlp-to" aria-label="Permalink to &quot;Organizations typically use DLP to:&quot;">​</a></h4><ul><li>Protect Personally Identifiable Information (PII) and comply with relevant regulations</li><li>Protect Intellectual Property critical for the organization</li><li>Achieve data visibility in large organizations</li><li>Secure mobile workforce and enforce security in Bring Your Own Device (BYOD) environments</li><li>Secure data on remote cloud systems</li></ul><p align="center"><img width="90%" src="https://miro.medium.com/max/720/1*FG9LR51eySVRQJUjhVv-9A.png"></p><h2 id="data-backup" tabindex="-1">Data Backup <a class="header-anchor" href="#data-backup" aria-label="Permalink to &quot;Data Backup&quot;">​</a></h2><p>Data backup plays a crucial role in maintaining business continuity by helping org. recover from IT disasters, security breaches, application failures, human error, etc.</p><p>All regulatory compliance such as COBIT, SSAE, SOCII, PCI-DSS, HIPPA, SOX, FINRA, FISMA, GDPR, etc. require business to maintain data backups of critical data for specified duration.</p><h3 id="backup-strategies" tabindex="-1">Backup Strategies <a class="header-anchor" href="#backup-strategies" aria-label="Permalink to &quot;Backup Strategies&quot;">​</a></h3><ol><li>Identifying the critical business data</li><li>Selecting the backup media</li><li>Selecting a backup technology</li><li>Selecting the appropriate RAID levels</li><li>Selecting an appropriate backup method</li></ol><h3 id="_3-backup-methods" tabindex="-1">3 Backup methods <a class="header-anchor" href="#_3-backup-methods" aria-label="Permalink to &quot;3 Backup methods&quot;">​</a></h3><h4 id="_1-cold-backup-🔵" tabindex="-1">1. Cold backup 🔵 <a class="header-anchor" href="#_1-cold-backup-🔵" aria-label="Permalink to &quot;1. Cold backup 🔵&quot;">​</a></h4><img width="40%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/29c5e018095b135baec32aaece84a900a43b23ca/cc-cold.png"><ul><li><strong>Empty site, no hardware, no data, no people</strong></li><li><strong>It takes weeks to bring online</strong></li><li>Basic office spaces (e.g building, chairs, AC...)</li><li>No operational equipment</li><li>Cheapest recovery site</li></ul><h4 id="_2-warm-backup-🟡" tabindex="-1">2. Warm backup 🟡 <a class="header-anchor" href="#_2-warm-backup-🟡" aria-label="Permalink to &quot;2. Warm backup 🟡&quot;">​</a></h4><img width="40%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/29c5e018095b135baec32aaece84a900a43b23ca/cc-warm.png"><ul><li><strong>Somewhere between cold and hot - Just enough to get going (Big room with rack space, you bring the hardware)</strong></li><li>Hardware is ready and waiting - you bring the software and data</li><li><strong>It takes days to bring online</strong></li><li>Operational equipment but little or no data</li></ul><h4 id="_3-hot-backup-🔴" tabindex="-1">3. Hot backup 🔴 <a class="header-anchor" href="#_3-hot-backup-🔴" aria-label="Permalink to &quot;3. Hot backup 🔴&quot;">​</a></h4><img width="40%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/29c5e018095b135baec32aaece84a900a43b23ca/cc-hot.png"><ul><li><strong>Exact replica of production systems</strong></li><li>Applications and software are constantly updated</li><li>Flip a switch and everyting moves</li><li><strong>It take hours to bring online</strong></li><li>Real-time synchronization</li><li>Almost all data ready to go - often just a quick update</li><li>Very expensive</li></ul><h2 id="penetration-test-basics" tabindex="-1"><u>Penetration Test - Basics</u> <a class="header-anchor" href="#penetration-test-basics" aria-label="Permalink to &quot;&lt;u&gt;Penetration Test - Basics&lt;/u&gt;&quot;">​</a></h2><blockquote><p><strong>This topic will be covered with details in <a href="https://github.com/Samsar4/CEH-v10-Study-Guide/blob/master/modules/14-Pentesting.md" target="_blank" rel="noreferrer">Chapter 14 - Pentesting</a>.</strong></p></blockquote><p><em>A penetration test, colloquially known as a pen test, pentest or ethical hacking, is an authorized simulated cyberattack on a computer system, performed to evaluate the security of the system.</em></p><blockquote><p>⚠️ <strong>Not to be confused with a vulnerability assessment.</strong></p></blockquote><ul><li>Clearly defined, full scale test of security controls</li><li>Phases <ul><li><strong>Preparation</strong> - Contracts and team determined</li><li><strong>Assessment</strong> - All hacking phases (reconnaissance, scanning, attacks, etc.)</li><li><strong>Post-Assessment</strong> - Reports &amp; conclusions</li></ul></li><li>Types <ul><li><strong>Black Box</strong> - Done without any knowledge of the system or network.</li><li><strong>White Box</strong> - When the attacker have complete knowledge of the system provided by the owner/target.</li><li><strong>Gray Box</strong> - When the attacker has some knowledge of the system and/or network</li></ul></li></ul><h2 id="laws-and-standards" tabindex="-1">Laws and Standards: <a class="header-anchor" href="#laws-and-standards" aria-label="Permalink to &quot;Laws and Standards:&quot;">​</a></h2><h3 id="osstm-compliance" tabindex="-1"><strong>OSSTM Compliance</strong> <a class="header-anchor" href="#osstm-compliance" aria-label="Permalink to &quot;**OSSTM Compliance**&quot;">​</a></h3><p><strong>&quot;Open Source Security Testing Methodology Manual&quot;</strong> maintained by ISECOM , defines three types of compliance.</p><ul><li><p><strong>Legislative</strong> - Deals with government regulations (Such as SOX and HIPAA).</p></li><li><p><strong>Contractual</strong> - Deals with industry / group requirement (Such as PCI DSS).</p></li><li><p><strong>Standards based</strong> - Deals with practices that must be followed by members of a given group/organization (Such as ITIL ,ISO and OSSTMM itself).</p></li><li><p><strong>OSSTM Controls</strong></p><ul><li><strong>OSSTM Class A - Interactive Controls</strong><ul><li><em>Authentication</em> - Provides for identification and authorization based on credentials.</li><li><em>Indemnification</em> - Provided contractual protection against loss or damages.</li><li><em>Subjugation</em> - Ensures that interactions occur according to processes defined by the asset owner.</li><li><em>Continuity</em> - Maintains interactivity with assets if corruption of failure occurs.</li><li><em>Resilience</em> - Protects assets from corruption and failure.</li></ul></li></ul></li><li><p><strong>OSSTM Class B - Process Controls</strong></p><ul><li><em>Non-repudiation</em> - Prevents participants from denying its actions</li><li><em>Confidentiality</em> - Ensures that only participants know of an asset</li><li><em>Privacy</em> - Ensures that only participants have access to the asset</li><li><em>Integrity</em> - Ensures that only participants know when assets and processes change</li><li><em>Alarm</em> - Notifies participants when interactions occur</li></ul></li></ul><h3 id="pci-dss" tabindex="-1"><strong>PCI-DSS</strong> <a class="header-anchor" href="#pci-dss" aria-label="Permalink to &quot;**PCI-DSS**&quot;">​</a></h3><p><strong>&quot;Payment Card Industry Data Security Standard&quot;</strong> Standard for organizations handling Credit Cards, ATM cards and other POS cards.</p><h3 id="iso-27001" tabindex="-1"><strong>ISO 27001</strong> <a class="header-anchor" href="#iso-27001" aria-label="Permalink to &quot;**ISO 27001**&quot;">​</a></h3><p>This International Standard has been prepared to provide requirements for establishing, implementing, maintaining and continually improving an information security management system.</p><h3 id="iso-27002-and-17799" tabindex="-1"><strong>ISO 27002 AND 17799</strong> <a class="header-anchor" href="#iso-27002-and-17799" aria-label="Permalink to &quot;**ISO 27002 AND 17799**&quot;">​</a></h3><p>Based on BS799 but focuses on security objectives and provides security controls based on industry best practice.</p><h3 id="hipaa" tabindex="-1"><strong>HIPAA</strong> <a class="header-anchor" href="#hipaa" aria-label="Permalink to &quot;**HIPAA**&quot;">​</a></h3><p><strong>&quot;Health Insurance Portability and Accountability Act&quot;</strong> a law that set&#39;s privacy standards to protect patient medical records and health information shared between doctors, hospitals and insurance providers.</p><h3 id="sox" tabindex="-1"><strong>SOX</strong> <a class="header-anchor" href="#sox" aria-label="Permalink to &quot;**SOX**&quot;">​</a></h3><p><strong>&quot;Sarbanes-Oxley Act&quot; Law</strong> that requires publicly traded companies to submit to independent audits and to properly disclose financial information.</p><h3 id="dmca" tabindex="-1">DMCA <a class="header-anchor" href="#dmca" aria-label="Permalink to &quot;DMCA&quot;">​</a></h3><p><strong>&quot;The Digital Millennium Copyright Act&quot;</strong> is a 1998 United States copyright law that implements two 1996 treaties of the World Intellectual Property Organization. It criminalizes production and dissemination of technology, devices, or services intended to circumvent measures that control access to copyrighted works.</p><h3 id="fisma" tabindex="-1"><strong>FISMA</strong> <a class="header-anchor" href="#fisma" aria-label="Permalink to &quot;**FISMA**&quot;">​</a></h3><p><strong>&quot;Federal Information Security Modernization Ac Of 2002&quot;</strong> A law updated in 2004 to codify the authority of the Department of Homeland Security with regard to implementation of information security policies. <em>(For GOV. agencies)</em></p><h3 id="nist-800-53" tabindex="-1"><strong>NIST-800-53</strong> <a class="header-anchor" href="#nist-800-53" aria-label="Permalink to &quot;**NIST-800-53**&quot;">​</a></h3><p>Catalogs security and privacy controls for federal information systems, created to help implementation of FISMA.</p><h3 id="fitara" tabindex="-1"><strong>FITARA</strong> <a class="header-anchor" href="#fitara" aria-label="Permalink to &quot;**FITARA**&quot;">​</a></h3><p><strong>&quot;Federal Information Technology Acquisition Reform Act&quot;</strong> A 2013 bill that was intended to change the framework that determines how the US GOV purchases technology.</p><h3 id="cobit" tabindex="-1"><strong>COBIT</strong> <a class="header-anchor" href="#cobit" aria-label="Permalink to &quot;**COBIT**&quot;">​</a></h3><p><strong>&quot;Control Object for Information and Related Technology&quot;</strong> IT Governance framework and toolset, created by ISACA and ITGI</p><h3 id="glba" tabindex="-1"><strong>GLBA</strong> <a class="header-anchor" href="#glba" aria-label="Permalink to &quot;**GLBA**&quot;">​</a></h3><p><strong>&quot;U.S Gramm-Leach-Bliley Act&quot;</strong> Law that protects the confidentiality and integrity of personal information that is collected by financial institutions.</p><h3 id="csirt" tabindex="-1"><strong>CSIRT</strong> <a class="header-anchor" href="#csirt" aria-label="Permalink to &quot;**CSIRT**&quot;">​</a></h3><p><strong>&quot;Computer Security Incident Response Team&quot;</strong> CSIRT provided a single point of contact when reporting computer security incidents</p><h3 id="itil" tabindex="-1"><strong>ITIL</strong> <a class="header-anchor" href="#itil" aria-label="Permalink to &quot;**ITIL**&quot;">​</a></h3><p><strong>&quot;Information Technology Infrastructure Library&quot;</strong> - An operational framework developed in the &#39;80s that standardizes IT management procedures</p>',185)]))}const p=t(n,[["render",r]]);export{h as __pageData,p as default};
